const xhr = new XMLHttpRequest();
xhr.open('GET', 'universidades.json', true);
xhr.onload = function () {
  if (xhr.status === 200) {
    const datos = JSON.parse(xhr.responseText);
    const lista = document.querySelector('#datos');

    datos.Universidades.forEach((universidad) => {
      const item = document.createElement('li');
      item.textContent = `${universidad.Nombre}: ${universidad.Pais}`;
      lista.appendChild(item);
    });
  }
};
xhr.send();
